const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const input=($json && typeof $json==='object' && !Array.isArray($json)) ? $json : {};
const incomingRun=(input.runContext && typeof input.runContext==='object' && !Array.isArray(input.runContext)) ? input.runContext : {};
const ruleContext=(input.ruleContext && typeof input.ruleContext==='object' && !Array.isArray(input.ruleContext))
  ? input.ruleContext
  : ((input.rule && typeof input.rule==='object' && !Array.isArray(input.rule)) ? input.rule : (input || {}));
const incomingTrace=(input.trace && typeof input.trace==='object' && !Array.isArray(input.trace)) ? input.trace : {};

const METRICS_DEFAULTS={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0};
const CFG={
  invoicePipeId:306859731,
  invoicePhaseId:341350484,
  itemPipeId:306859915,
  itemPhaseId:341351580,
  activeItemPhaseId:'341306826',
  ruleLinkFieldId:'id_da_regra_de_faturamento',
  competenciaFieldId:'data_de_compet_ncia'
};

const assertPositiveInt=(value,name)=>{
  const n=Number(value);
  if(!Number.isInteger(n) || n<=0){
    throw new Error('Config hardcoded invalida: '+name);
  }
  return n;
};
assertPositiveInt(CFG.invoicePipeId,'invoicePipeId');
assertPositiveInt(CFG.invoicePhaseId,'invoicePhaseId');
assertPositiveInt(CFG.itemPipeId,'itemPipeId');
assertPositiveInt(CFG.itemPhaseId,'itemPhaseId');
if(!String(CFG.activeItemPhaseId||'').trim()){
  throw new Error('Config hardcoded invalida: activeItemPhaseId');
}

const toFiniteNumber=(v,fallback)=>{
  const n=Number(v);
  return Number.isFinite(n) ? n : fallback;
};
const cleanToken=(value)=>{
  if(value===undefined || value===null) return '';
  return String(value).trim();
};
const isBlankToken=(value)=>{
  const s=cleanToken(value).toLowerCase();
  return s==='' || s==='null' || s==='undefined' || s==='nan';
};
const isIsoDate=(value)=>/^\d{4}-\d{2}-\d{2}$/.test(cleanToken(value));

sd.procRuns=(sd.procRuns && typeof sd.procRuns==='object' && !Array.isArray(sd.procRuns)) ? sd.procRuns : {};
for(const [key,state] of Object.entries(sd.procRuns)){
  const startedAt=state?.ruleTmp?.startedAt || state?.createdAt || null;
  const ageMs=startedAt ? (Date.now()-Date.parse(startedAt)) : Number.POSITIVE_INFINITY;
  if(!Number.isFinite(ageMs) || ageMs > 24*60*60*1000){
    delete sd.procRuns[key];
  }
}

const run={...incomingRun};
run.metrics=(run.metrics && typeof run.metrics==='object' && !Array.isArray(run.metrics)) ? run.metrics : {};
for(const [k,v] of Object.entries(METRICS_DEFAULTS)){
  run.metrics[k]=toFiniteNumber(run.metrics[k],v);
}
run.metrics.unexpectedStateErrors=Number(run.metrics.unexpectedStateErrors || 0);
run.logs=Array.isArray(run.logs) ? run.logs : [];
run.errors=Array.isArray(run.errors) ? run.errors : [];

const startedAt=new Date().toISOString();
const baseLogs=run.logs.slice();
const baseErrors=run.errors.slice();
const isPrepSummary=input.itemType==='prep_summary' || input.kind==='prep_summary' || input.prepSummary===true;
const rawRuleId=isPrepSummary ? '__prep_summary__' : (ruleContext.ruleId ?? ruleContext.id ?? null);
const normalizedRuleId=cleanToken(rawRuleId);
const procKey=[execId,(normalizedRuleId||'__no_rule__'),String(Date.now()),String(Math.floor(Math.random()*1e9))].join(':');

const trace={
  parentExecutionId: incomingTrace.parentExecutionId!=null
    ? String(incomingTrace.parentExecutionId)
    : (run.executionId!=null ? String(run.executionId) : null),
  workflowExecutionId: execId,
  procKey
};

const rt={
  kind:isPrepSummary ? 'prep_summary' : 'rule_result',
  isPrepSummary,
  ruleId:normalizedRuleId,
  procKey,
  inputTrace:trace,
  ruleTitle:String(ruleContext.ruleTitle||ruleContext.title||''),
  diaGeracao:String(ruleContext.diaGeracao||''),
  competenciaYMD:String(ruleContext.competenciaYMD||run.competenciaYMD||''),
  compStart:String(ruleContext.compStart||run.compStart||''),
  compEnd:String(ruleContext.compEnd||run.compEnd||''),
  itemTemplateIds:isPrepSummary ? [] : (Array.isArray(ruleContext.itemTemplateIds)?ruleContext.itemTemplateIds.map((x)=>String(x)):[]),
  ruleFields:ruleContext.ruleFields||{},
  prefetchDecision:String(ruleContext.prefetchDecision||'new_rule_candidate'),
  items:[],
  eligibleItems:[],
  createdItemIds:[],
  invoiceId:null,
  existingInvoiceId:null,
  totals:{brl:0,usd:0},
  skipItemCreation:false,
  hasItemErrors:false,
  hasCriticalItemErrors:false,
  hasInvoiceError:false,
  finalStatus:isPrepSummary ? 'prep_summary' : null,
  statusReason:isPrepSummary ? 'prep_summary_context_item' : null,
  validationErrors:[],
  invoiceCreationCounted:false,
  prepContext:(input.result && typeof input.result==='object' && !Array.isArray(input.result) && input.result.prepContext && typeof input.result.prepContext==='object')
    ? input.result.prepContext
    : ((input.prepContext && typeof input.prepContext==='object' && !Array.isArray(input.prepContext)) ? input.prepContext : null),
  baseMetrics:{...run.metrics},
  baseLogs,
  baseErrors,
  logStartIndex:run.logs.length,
  errorStartIndex:run.errors.length,
  startedAt,
  config:CFG,
  createContext:null
};

run.logs.push({
  ts:startedAt,
  level:'info',
  event:'rule_start',
  ruleId:isBlankToken(rt.ruleId)?null:rt.ruleId,
  kind:rt.kind,
  itemsPlanned:rt.itemTemplateIds.length,
  prefetchDecision:rt.prefetchDecision,
  hasValidationErrors:false,
  contractVersion:'fin_v2'
});

if(isPrepSummary){
  run.logs.push({
    ts:startedAt,
    level:'info',
    event:'prep_summary_received',
    ruleId:rt.ruleId,
    prepContext:rt.prepContext
  });
  const storedState={run,ruleTmp:rt,createdAt:startedAt};
  sd.procRuns[procKey]=storedState;
  sd.procRuns[execId]=storedState;
  return [{json:{
    contractVersion:'fin_v2',
    itemType:'prep_summary',
    trace,
    runContext:run,
    ruleContext:null,
    result:{status:'processed',reason:'prep_summary_context_item'},
    rule:ruleContext,
    procKey,
    prepSummary:true,
    invoiceId:null,
    invoiceCreated:false
  }}];
}

const validationErrors=[];
if(isBlankToken(rt.ruleId)){
  validationErrors.push('missing_rule_id');
}
if(!isIsoDate(rt.competenciaYMD)){
  validationErrors.push('invalid_competencia_ymd');
}
if(!isIsoDate(rt.compStart)){
  validationErrors.push('invalid_comp_start');
}
if(!isIsoDate(rt.compEnd)){
  validationErrors.push('invalid_comp_end');
}
if(isIsoDate(rt.compStart) && isIsoDate(rt.compEnd) && rt.compStart > rt.compEnd){
  validationErrors.push('comp_start_after_comp_end');
}

if(!Array.isArray(ruleContext.itemTemplateIds)){
  run.logs.push({
    ts:startedAt,
    level:'warn',
    event:'rule_item_template_ids_normalized',
    ruleId:isBlankToken(rt.ruleId)?null:rt.ruleId,
    reason:'itemTemplateIds_not_array'
  });
}

if(validationErrors.length>0){
  rt.validationErrors=validationErrors;
  rt.hasInvoiceError=true;
  rt.skipItemCreation=true;
  rt.finalStatus='invoice_error';
  rt.statusReason='invalid_rule_input';
  rt.itemTemplateIds=[];

  run.metrics.unexpectedStateErrors += 1;
  run.errors.push({
    ts:startedAt,
    stage:'rule_init_validation',
    ruleId:isBlankToken(rt.ruleId)?null:rt.ruleId,
    reason:'invalid_rule_input',
    trace,
    details:{
      validationErrors,
      rulePreview:{
        ruleId:rawRuleId ?? null,
        competenciaYMD:rt.competenciaYMD,
        compStart:rt.compStart,
        compEnd:rt.compEnd,
        itemTemplateIdsCount:Array.isArray(ruleContext.itemTemplateIds)?ruleContext.itemTemplateIds.length:null
      }
    }
  });
  run.logs.push({
    ts:startedAt,
    level:'error',
    event:'rule_invalid_input',
    ruleId:isBlankToken(rt.ruleId)?null:rt.ruleId,
    reasons:validationErrors
  });
}

const storedState={run,ruleTmp:rt,createdAt:startedAt};
sd.procRuns[procKey]=storedState;
sd.procRuns[execId]=storedState;
return [{json:{
  contractVersion:'fin_v2',
  itemType:'rule_candidate',
  trace,
  runContext:run,
  ruleContext,
  result:{status:'processed',reason:'ready_for_processing'},
  rule:ruleContext,
  procKey,
  invoiceId:null,
  invoiceCreated:false
}}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const procKey=String((($json && typeof $json==='object' && !Array.isArray($json)) ? $json.procKey : '') || execId);
const state=sd.procRuns?.[procKey] || sd.procRuns?.[execId];
if(!state){
  return [{json:{...$json,skipRule:true,reason:'missing_processing_state',missingProcessingState:true,missingProcessingStateAt:'Rule: Skip (sem itens)',procKey,executionId:execId,nodeName:'Rule: Skip (sem itens)'}}];
}
const rt=state.ruleTmp;
const run=state.run;

let reason='no_item_template_ids';
if(rt){
  if(rt.isPrepSummary===true){
    rt.finalStatus='prep_summary';
    rt.statusReason='prep_summary_context_item';
    reason='prep_summary_context_item';
  }else if(rt.finalStatus==='invoice_error'){
    reason='blocked_by_validation_or_precheck_error';
  }else{
    rt.finalStatus='skipped_no_items';
    rt.statusReason='rule_has_no_item_templates';
  }
}

run.logs.push({
  ts:new Date().toISOString(),
  level:(reason==='blocked_by_validation_or_precheck_error' ? 'warn' : 'info'),
  event:'rule_skip_no_items',
  ruleId:rt?rt.ruleId:null,
  reason,
  validationErrors:(rt && Array.isArray(rt.validationErrors)) ? rt.validationErrors : []
});

return [{json:$json}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const procKey=String((($json && typeof $json==='object' && !Array.isArray($json)) ? $json.procKey : '') || execId);
const state=sd.procRuns?.[procKey] || sd.procRuns?.[execId];
if(!state){
  return [];
}
const rt=state.ruleTmp;
const run=state.run;
const chunkSize=20;
const ids=Array.isArray(rt?.itemTemplateIds)?rt.itemTemplateIds:[];
rt.items=[];
const chunks=[];
for(let i=0;i<ids.length;i+=chunkSize){
  chunks.push(ids.slice(i,i+chunkSize));
}
run.logs.push({ts:new Date().toISOString(),level:'info',event:'rule_chunkify',ruleId:rt?rt.ruleId:null,chunks:chunks.length,chunkSize});
return chunks.map((c,idx)=>({json:{procKey,chunkIds:c,chunkIndex:idx+1,chunkTotal:chunks.length}}));

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const procKey=String((($json && typeof $json==='object' && !Array.isArray($json)) ? $json.procKey : '') || execId);
const state=sd.procRuns?.[procKey] || sd.procRuns?.[execId];
if(!state){
  return [];
}
const rt=state.ruleTmp;
const run=state.run;

const gqlErrors=Array.isArray($json.errors) ? $json.errors : [];
if(gqlErrors.length>0){
  run.errors.push({
    ts:new Date().toISOString(),
    stage:'fetch_items_batch',
    ruleId:rt?rt.ruleId:null,
    details:gqlErrors
  });
  run.logs.push({
    ts:new Date().toISOString(),
    level:'error',
    event:'rule_items_batch_error',
    ruleId:rt?rt.ruleId:null,
    errorsCount:gqlErrors.length
  });
  throw new Error('Fetch itens (batch) retornou GraphQL errors: '+JSON.stringify(gqlErrors));
}

if(!$json.data || typeof $json.data!=='object' || Array.isArray($json.data)){
  run.metrics.unexpectedStateErrors=Number(run.metrics.unexpectedStateErrors || 0) + 1;
  run.errors.push({
    ts:new Date().toISOString(),
    stage:'fetch_items_batch',
    ruleId:rt?rt.ruleId:null,
    details:'invalid_batch_shape'
  });
  run.logs.push({
    ts:new Date().toISOString(),
    level:'error',
    event:'rule_items_batch_invalid_shape',
    ruleId:rt?rt.ruleId:null,
    payloadKeys:Object.keys($json||{})
  });
  throw new Error('Formato invalido no FIN-02: Fetch itens (batch).');
}

const data=$json.data;
const cards=[];
let missingCount=0;
for(const k of Object.keys(data)){
  const v=data[k];
  if(v && v.id){
    cards.push(v);
  }else{
    missingCount += 1;
  }
}

rt.items.push(...cards);
run.metrics.itemBatchQueries=Number(run.metrics.itemBatchQueries || 0) + 1;
run.metrics.itemsFetched=Number(run.metrics.itemsFetched || 0) + cards.length;

if(missingCount>0){
  run.logs.push({
    ts:new Date().toISOString(),
    level:'warn',
    event:'rule_items_batch_partial_missing',
    ruleId:rt?rt.ruleId:null,
    missingCount,
    totalEntries:Object.keys(data).length
  });
}
if(cards.length===0){
  run.logs.push({
    ts:new Date().toISOString(),
    level:'warn',
    event:'rule_items_batch_empty',
    ruleId:rt?rt.ruleId:null
  });
}

run.logs.push({
  ts:new Date().toISOString(),
  level:'info',
  event:'rule_items_batch_fetched',
  ruleId:rt?rt.ruleId:null,
  count:cards.length
});

return [{json:{procKey,ok:true,fetchedCount:cards.length,missingCount}}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const procKey=String((($json && typeof $json==='object' && !Array.isArray($json)) ? $json.procKey : '') || execId);
const state=sd.procRuns?.[procKey] || sd.procRuns?.[execId];
if(!state){
  return [{json:{...$json,skipRule:true,reason:'missing_processing_state',missingProcessingState:true,missingProcessingStateAt:'Rule: Filtrar itens + montar fatura',procKey,executionId:execId,nodeName:'Rule: Filtrar itens + montar fatura'}}];
}
const run=state.run;
const rt=state.ruleTmp;
const compStart=String(rt.compStart || '');
const compEnd=String(rt.compEnd || '');
const activePhase=String(rt.config.activeItemPhaseId);
const items=Array.isArray(rt.items) ? rt.items : [];
const eligible=[];
const now=()=>new Date().toISOString();
const log=(obj)=>run.logs.push({ts:now(),...obj});
const pushError=(details)=>run.errors.push({ts:now(),stage:'filter_items',ruleId:rt?rt.ruleId:null,details});

const baseItemBatchQueries=Number(rt?.baseMetrics?.itemBatchQueries || 0);
const currentItemBatchQueries=Number(run?.metrics?.itemBatchQueries || 0);
const batchQueriesDelta=Math.max(0,currentItemBatchQueries-baseItemBatchQueries);
if(Array.isArray(rt.itemTemplateIds) && rt.itemTemplateIds.length>0 && items.length===0 && batchQueriesDelta===0){
  rt.finalStatus='invoice_error';
  rt.statusReason='items_not_fetched_before_filter';
  rt.hasInvoiceError=true;
  rt.skipItemCreation=true;
  run.metrics.unexpectedStateErrors=Number(run.metrics.unexpectedStateErrors || 0) + 1;
  pushError({reason:'items_not_fetched_before_filter',itemTemplateIdsCount:rt.itemTemplateIds.length,batchQueriesDelta,baseItemBatchQueries,currentItemBatchQueries});
  log({
    level:'error',
    event:'rule_items_fetch_not_executed_before_filter',
    ruleId:rt.ruleId,
    itemTemplateIdsCount:rt.itemTemplateIds.length,
    batchQueriesDelta,
    baseItemBatchQueries,
    currentItemBatchQueries,
    reason:'possible_split_loop_miswire'
  });
  return [{json:{procKey,skipRule:true,reason:'items_not_fetched_before_filter'}}];
}
const isIsoDate=(value)=>/^\d{4}-\d{2}-\d{2}$/.test(String(value||'').slice(0,10));

if(!isIsoDate(compStart) || !isIsoDate(compEnd) || compStart>compEnd){
  const reason=!isIsoDate(compStart) || !isIsoDate(compEnd) ? 'invalid_competencia_window' : 'comp_start_after_comp_end';
  rt.finalStatus='invoice_error';
  rt.statusReason=reason;
  rt.hasInvoiceError=true;
  rt.skipItemCreation=true;
  run.metrics.unexpectedStateErrors=Number(run.metrics.unexpectedStateErrors || 0) + 1;
  pushError({reason,compStart,compEnd});
  log({level:'error',event:'rule_invalid_comp_window',ruleId:rt.ruleId,reason,compStart,compEnd});
  return [{json:{procKey,skipRule:true,reason}}];
}

const fieldMap=(fields)=>{const m={};for(const f of (fields||[])){const fid=f&&f.field?f.field.id:null;if(fid)m[fid]=f;}return m;};
const scalar=(f)=>{if(!f)return null;const rv=f.report_value;return (rv!==undefined&&rv!==null&&String(rv).trim()!=='')?rv:f.value;};
const parseNum=(v)=>{if(v===undefined||v===null)return 0; if(typeof v==='number'&&Number.isFinite(v))return v; let s=String(v).trim(); if(!s)return 0; s=s.replace(/[^0-9,.-]/g,''); if(!s)return 0; if(s.includes(',')&&s.includes('.')){ if(s.lastIndexOf(',')>s.lastIndexOf('.')){ s=s.replace(/\./g,'').replace(',','.'); } else { s=s.replace(/,/g,''); } } else if(s.includes(',')){ s=s.replace(',','.'); } const n=Number(s); return Number.isFinite(n)?n:0; };

const skipCounters={
  invalidItem:0,
  inactivePhase:0,
  notStarted:0,
  ended:0,
  parceladoDone:0,
  parceladoInvalidTotal:0
};

let totalBrl=0;
let totalUsd=0;
for(const c of items){
  if(!c || !c.id){
    skipCounters.invalidItem += 1;
    log({level:'warn',event:'item_skip_invalid_shape',ruleId:rt.ruleId});
    continue;
  }

  const templateItemId=String(c.id);
  const phaseId=c.current_phase&&c.current_phase.id?String(c.current_phase.id):'';
  if(phaseId!==activePhase){
    skipCounters.inactivePhase += 1;
    log({level:'info',event:'item_skip_inactive',ruleId:rt.ruleId,templateItemId,phaseId,expectedPhaseId:activePhase,reason:'phase_not_active'});
    continue;
  }

  const fm=fieldMap(c.fields);
  const start=(scalar(fm['data_de_in_cio_do_faturamento'])||'').toString().slice(0,10);
  const end=(scalar(fm['data_de_fim_do_faturamento'])||'').toString().slice(0,10);
  if(start && start>compEnd){
    skipCounters.notStarted += 1;
    log({level:'info',event:'item_skip_not_started',ruleId:rt.ruleId,templateItemId,start,compEnd,reason:'billing_start_after_comp_end'});
    continue;
  }
  if(end && end<compStart){
    skipCounters.ended += 1;
    log({level:'info',event:'item_skip_ended',ruleId:rt.ruleId,templateItemId,end,compStart,reason:'billing_end_before_comp_start'});
    continue;
  }

  const periodicidade=String(scalar(fm['periodicidade'])||'').trim();
  let parcelado=null;
  if(periodicidade==='Parcelado'){
    const pagas=parseInt(String(scalar(fm['parcelas_pagas'])||'0').match(/[0-9]+/)?String(scalar(fm['parcelas_pagas'])).match(/[0-9]+/)[0]:'0',10);
    const total=parseInt(String(scalar(fm['quantidade_de_parcelas_totais'])||'0').match(/[0-9]+/)?String(scalar(fm['quantidade_de_parcelas_totais'])).match(/[0-9]+/)[0]:'0',10);
    if(!(total>0)){
      skipCounters.parceladoInvalidTotal += 1;
      rt.hasItemErrors=true;
      rt.hasCriticalItemErrors=true;
      pushError({reason:'parcelado_invalid_total',templateItemId,pagas,total});
      log({level:'error',event:'item_skip_parcelado_invalid_total',ruleId:rt.ruleId,templateItemId,pagas,total,reason:'invalid_total_parcelas'});
      continue;
    }
    if(pagas>=total){
      skipCounters.parceladoDone += 1;
      log({level:'info',event:'item_skip_parcelado_done',ruleId:rt.ruleId,templateItemId,pagas,total,reason:'all_installments_already_billed'});
      continue;
    }
    parcelado={newParcelasPagas:pagas+1};
  }

  const currency=String(scalar(fm['moeda_da_fatura'])||'').trim();
  let brl=0;
  let usd=0;
  if(currency.startsWith('USD')){
    usd=parseNum(scalar(fm['valor_total_do_item_com_descontos_usd'])??scalar(fm['subtotal_do_item_usd']));
  }else if(currency.startsWith('BRL')){
    brl=parseNum(scalar(fm['valor_total_do_item_com_descontos_brl'])??scalar(fm['subtotal_do_item_brl']));
  }else{
    brl=parseNum(scalar(fm['valor_total_do_item_com_descontos_brl'])??scalar(fm['subtotal_do_item_brl']));
    usd=parseNum(scalar(fm['valor_total_do_item_com_descontos_usd'])??scalar(fm['subtotal_do_item_usd']));
  }

  totalBrl+=brl;
  totalUsd+=usd;
  eligible.push({templateItemId,title:String(c.title||''),fields:c.fields||[],periodicidade,currency,parcelado,totalBrl:brl,totalUsd:usd});
}

rt.eligibleItems=eligible;
rt.totals={brl:totalBrl,usd:totalUsd};
log({
  level:'info',
  event:'rule_items_filtered',
  ruleId:rt.ruleId,
  fetched:items.length,
  eligible:eligible.length,
  skipCounters
});

if(eligible.length===0){
  rt.finalStatus='skipped_no_eligible_items';
  rt.statusReason='no_eligible_items_after_filters';
  log({level:'info',event:'rule_skip_no_eligible_items',ruleId:rt.ruleId,reason:'no_eligible_items_after_filters',skipCounters});
  return [{json:{procKey,skipRule:true,reason:'no_eligible_items'}}];
}

const rf=rt.ruleFields||{};
const pickScalar=(f)=>{if(!f)return null;const rv=f.report_value;return (rv!==undefined&&rv!==null&&String(rv).trim()!=='')?rv:f.value;};
const extractIds=(f)=>{if(!f)return [];const av=f.array_value;const ids=[];const push=(x)=>{if(x===undefined||x===null)return; if(typeof x==='object'){if(x.id!=null)ids.push(String(x.id)); else if(x.value!=null)ids.push(String(x.value)); else if(x.label!=null)ids.push(String(x.label)); else ids.push(JSON.stringify(x));} else ids.push(String(x));}; if(Array.isArray(av)){for(const x of av)push(x);} else {const v=pickScalar(f); if(Array.isArray(v)){for(const x of v)push(x);} else if(typeof v==='string'){const ms=v.match(/[0-9]+/g); if(ms)for(const x of ms)ids.push(String(x)); else if(v.trim()!=='')ids.push(v.trim());} else if(v!=null)push(v);} return Array.from(new Set(ids.filter((s)=>s&&String(s).trim()!==''))).map(String);};
const extractList=(f)=>{if(!f)return [];const av=f.array_value;let out=[];if(Array.isArray(av))out=av.map(x=>String(x));else{const v=pickScalar(f);if(Array.isArray(v))out=v.map(x=>String(x));else if(typeof v==='string'){const s=v.trim();if(!s)out=[];else if(s.startsWith('[')){try{const p=JSON.parse(s);if(Array.isArray(p))out=p.map(x=>String(x));else out=[String(p)];}catch(_){out=s.split(',').map(x=>x.trim()).filter(Boolean);}}else out=s.split(',').map(x=>x.trim()).filter(Boolean);}else if(v!=null)out=[String(v)];}return Array.from(new Set(out.filter(Boolean)));};

