const mapStatus=()=>{
  const finalStatus=String(rt.finalStatus || '');
  const statusReason=String(rt.statusReason || '').trim();

  if(rt.isPrepSummary===true){
    return {status:'processed',reason:'prep_summary_context_item'};
  }

  if(finalStatus==='skipped_existing_invoice'){
    return {status:'skipped',reason:'existing_invoice_found'};
  }
  if(finalStatus==='skipped_no_items'){
    return {status:'skipped',reason:'rule_has_no_item_templates'};
  }
  if(finalStatus==='skipped_no_eligible_items'){
    return {status:'skipped',reason:'no_eligible_items_after_filters'};
