  if(rt.invoiceId && rt.hasItemErrors===true){
    return {status:'failed',reason:'item_partial_error'};
  }

  if(rt.hasInvoiceError===true || rt.hasItemErrors===true){
    return {status:'failed',reason:statusReason || 'processing_failed'};
  }

  if(rt.skipItemCreation===true && !rt.invoiceId && !rt.existingInvoiceId){
    return {status:'failed',reason:statusReason || 'no_created_items_for_invoice'};
  }

  if(!rt.invoiceId && rt.existingInvoiceId){
